import React, { useEffect, useState } from 'react';
import AppLayout from '../../components/shared/AppLayout';
import LoadingSpinner from '../../components/shared/LoadingSpinner';
import api from '../../utils/api';
import toast from 'react-hot-toast';
import { format } from 'date-fns';

export default function AdminUsers() {
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [selectedUser, setSelectedUser] = useState(null);
  const [userScores, setUserScores] = useState([]);
  const [scoresLoading, setScoresLoading] = useState(false);
  const [editingScore, setEditingScore] = useState(null);
  const [editVal, setEditVal] = useState('');

  useEffect(() => {
    api.get('/admin/users')
      .then(r => setUsers(r.data.users))
      .finally(() => setLoading(false));
  }, []);

  const openUser = async (u) => {
    setSelectedUser(u);
    setScoresLoading(true);
    try {
      const r = await api.get(`/admin/users/${u._id}/scores`);
      setUserScores(r.data.scores);
    } finally {
      setScoresLoading(false);
    }
  };

  const saveScore = async (scoreId) => {
    if (!editVal || editVal < 1 || editVal > 45) return toast.error('Score must be 1–45');
    try {
      await api.put(`/admin/scores/${scoreId}`, { score: Number(editVal) });
      setUserScores(p => p.map(s => s._id === scoreId ? { ...s, score: Number(editVal) } : s));
      setEditingScore(null);
      toast.success('Score updated');
    } catch {
      toast.error('Failed to update score');
    }
  };

  const updateSub = async (userId, status) => {
    try {
      await api.put(`/admin/users/${userId}/subscription`, { subscription_status: status });
      setUsers(p => p.map(u => u._id === userId ? { ...u, subscription_status: status } : u));
      if (selectedUser?._id === userId) setSelectedUser(p => ({ ...p, subscription_status: status }));
      toast.success('Subscription updated');
    } catch {
      toast.error('Failed to update');
    }
  };

  const filtered = users.filter(u =>
    u.name.toLowerCase().includes(search.toLowerCase()) ||
    u.email.toLowerCase().includes(search.toLowerCase())
  );

  const subBadge = (status) => {
    if (status === 'active') return 'badge-active';
    if (status === 'cancelled') return 'bg-red-900/30 border border-red-700/40 text-red-400 text-xs px-2 py-0.5 rounded-full';
    return 'badge-inactive';
  };

  return (
    <AppLayout>
      <div className="max-w-6xl mx-auto space-y-6 animate-slide-up">
        <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
          <div>
            <h1 className="page-title">Users</h1>
            <p className="text-charcoal-400 mt-1">{users.length} registered players</p>
          </div>
          <input
            type="text"
            className="input-field max-w-xs"
            placeholder="Search users..."
            value={search}
            onChange={e => setSearch(e.target.value)}
          />
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-5 gap-6">
          {/* Users table */}
          <div className="lg:col-span-3">
            <div className="card p-0 overflow-hidden">
              <table className="w-full">
                <thead className="border-b border-charcoal-800/60">
                  <tr>
                    <th className="table-header">User</th>
                    <th className="table-header">Plan</th>
                    <th className="table-header">Status</th>
                    <th className="table-header">Charity</th>
                  </tr>
                </thead>
                <tbody>
                  {loading ? (
                    <tr><td colSpan={4} className="py-12 text-center"><LoadingSpinner /></td></tr>
                  ) : filtered.length === 0 ? (
                    <tr><td colSpan={4} className="py-12 text-center text-charcoal-500">No users found</td></tr>
                  ) : filtered.map(u => (
                    <tr
                      key={u._id}
                      className={`table-row cursor-pointer ${selectedUser?._id === u._id ? 'bg-forest-900/20' : ''}`}
                      onClick={() => openUser(u)}
                    >
                      <td className="table-cell">
                        <div className="flex items-center gap-2.5">
                          <div className="w-8 h-8 rounded-full bg-forest-800 flex items-center justify-center text-xs font-bold text-forest-300 shrink-0">
                            {u.name[0].toUpperCase()}
                          </div>
                          <div className="min-w-0">
                            <div className="text-white text-sm font-medium truncate">{u.name}</div>
                            <div className="text-charcoal-500 text-xs truncate">{u.email}</div>
                          </div>
                        </div>
                      </td>
                      <td className="table-cell capitalize">{u.plan || '—'}</td>
                      <td className="table-cell">
                        <span className={subBadge(u.subscription_status)}>{u.subscription_status}</span>
                      </td>
                      <td className="table-cell text-xs truncate max-w-[100px]">
                        {u.charity_id?.name || '—'}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>

          {/* User detail panel */}
          <div className="lg:col-span-2">
            {!selectedUser ? (
              <div className="card text-center py-12">
                <div className="text-3xl mb-3">👆</div>
                <p className="text-charcoal-400 text-sm">Click a user to view details</p>
              </div>
            ) : (
              <div className="card space-y-5">
                {/* User info */}
                <div className="flex items-center gap-3">
                  <div className="w-12 h-12 rounded-full bg-forest-800 flex items-center justify-center text-lg font-bold text-forest-300">
                    {selectedUser.name[0].toUpperCase()}
                  </div>
                  <div>
                    <div className="font-semibold text-white">{selectedUser.name}</div>
                    <div className="text-xs text-charcoal-500">{selectedUser.email}</div>
                  </div>
                </div>

                {/* Subscription controls */}
                <div>
                  <p className="label">Subscription Status</p>
                  <div className="flex gap-2 flex-wrap">
                    {['active', 'inactive', 'cancelled'].map(s => (
                      <button
                        key={s}
                        onClick={() => updateSub(selectedUser._id, s)}
                        className={`text-xs px-3 py-1.5 rounded-lg border font-medium transition-all capitalize ${
                          selectedUser.subscription_status === s
                            ? 'bg-forest-700 border-forest-600 text-white'
                            : 'border-charcoal-700 text-charcoal-400 hover:border-charcoal-600'
                        }`}
                      >
                        {s}
                      </button>
                    ))}
                  </div>
                </div>

                {/* Scores */}
                <div>
                  <p className="label">Scores</p>
                  {scoresLoading ? (
                    <LoadingSpinner size="sm" />
                  ) : userScores.length === 0 ? (
                    <p className="text-charcoal-500 text-xs">No scores</p>
                  ) : (
                    <div className="space-y-2">
                      {userScores.map(score => (
                        <div key={score._id} className="flex items-center gap-2 p-2.5 rounded-lg bg-charcoal-800/40">
                          {editingScore === score._id ? (
                            <>
                              <input
                                type="number"
                                className="input-field py-1 px-2 text-sm w-20"
                                value={editVal}
                                onChange={e => setEditVal(e.target.value)}
                                min="1"
                                max="45"
                                autoFocus
                              />
                              <button onClick={() => saveScore(score._id)} className="text-xs text-forest-400 hover:text-forest-300 font-medium">Save</button>
                              <button onClick={() => setEditingScore(null)} className="text-xs text-charcoal-500 hover:text-charcoal-300">Cancel</button>
                            </>
                          ) : (
                            <>
                              <div className="score-bubble bg-charcoal-700 text-charcoal-300 w-9 h-9 text-xs">{score.score}</div>
                              <div className="flex-1">
                                <div className="text-xs text-white">{score.score} pts</div>
                                <div className="text-xs text-charcoal-500">{format(new Date(score.date), 'MMM d, yyyy')}</div>
                              </div>
                              <button
                                onClick={() => { setEditingScore(score._id); setEditVal(score.score); }}
                                className="text-xs text-charcoal-500 hover:text-charcoal-300 p-1"
                              >
                                ✏️
                              </button>
                            </>
                          )}
                        </div>
                      ))}
                    </div>
                  )}
                </div>

                <div className="pt-3 border-t border-charcoal-800/60 text-xs text-charcoal-600">
                  Joined {format(new Date(selectedUser.createdAt), 'MMM d, yyyy')}
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    </AppLayout>
  );
}
